nodes.statement_tex:
\label{thm:landau-addition-exists-unique}
To every pair $x, y \in \mathbb{N}$ we may assign, in exactly one way,
a natural number $x + y$, called the \emph{sum} of $x$ and $y$, such that:
\begin{enumerate}
  \item[\textbf{A6.}] $x + 1 = x'$ \quad for all $x \in \mathbb{N}$,
  \item[\textbf{A7.}] $x + y' = (x + y)'$ \quad for all $x, y \in \mathbb{N}$.
\end{enumerate}

\label{thm:landau-pred-unique}
For every $x \in \mathbb{N}$ with $x \neq 1$, there exists a unique
$u \in \mathbb{N}$ such that $x = u'$.

\label{lem:predecessor}
Let $a$ be a positive natural number. Then there exists exactly one
$b \in \mathbb{N}$ such that $b\pp = a$.

\label{prop:order-basic}
Let $a, b, c \in \mathbb{N}$.
\begin{enumerate}
  \item[(a)] \textbf{Reflexive.} $a \geq a$.
  \item[(b)] \textbf{Transitive.} If $a \geq b$ and $b \geq c$, then $a \geq c$.
  \item[(c)] \textbf{Anti-symmetric.} If $a \geq b$ and $b \geq a$, then $a = b$.
  \item[(d)] \textbf{Addition preserves order.}
    $a \geq b \iff a + c \geq b + c$.
  \item[(e)] $a < b \iff a\pp \leq b$.
  \item[(f)] $a < b \iff b = a + d$ for some positive $d$.
\end{enumerate}

\label{prop:pos-add-pos}
If $a$ is positive and $b \in \mathbb{N}$, then $a + b$ is positive
(and hence $b + a$ is positive by commutativity).

