\label{thm:stern-brocot}

Every positive rational number appears exactly once in the
Stern–Brocot tree obtained by repeated mediant insertion.

\label{thm:cantor}
For any set $A$, there is no surjection $A \to \mathcal{P}(A)$. In
particular, $|A| < |\mathcal{P}(A)|$.

\label{thm:countable-union}
Let $\{A_n\}_{n \in \mathbb{N}}$ be a countable family of countable sets.
Then $\bigcup_{n=1}^{\infty} A_n$ is countable.

\label{def:index}
The \emph{index} of $R$ on $A$ is the cardinality $|A/R|$, i.e.\ the number
of equivalence classes.

\label{def:constant}
$f : A \to B$ is \emph{constant} if there exists $b_0 \in B$ with
$f(a) = b_0$ for all $a \in A$.

\label{prop:induced-preorder}
For any function $f : A \to B$ and partial order $(B, \leq')$, the relation
$\leq_f$ is a preorder on $A$: it is reflexive and transitive.

\label{def:comparable}
In an ordered set $(A,\leq)$, elements $a,b \in A$ are \emph{comparable} if
$a \leq b$ or $b \leq a$; they are \emph{incomparable} if neither holds.

\label{prop:embedding-iso}
If $f : (A, \leq) \to (B, \leq')$ is an order embedding, then $f$ is an
order isomorphism from $(A, \leq)$ to the suborder $(f(A), \leq'_{f(A)})$.

\label{def:antisymmetric}
$R$ is \emph{antisymmetric} if mutual relation implies equality:
\[
\forall a,b \in A, \;
\bigl( (a,b) \in R \land (b,a) \in R \bigr) \rightarrow a = b.
\]

\label{def:asymmetric}
$R$ is \emph{asymmetric} if related pairs never commute:
\[
\forall a,b \in A, \;
(a,b) \in R \rightarrow (b,a) \notin R.
\]

\label{def:total-rel}
$R$ is \emph{total} (or \emph{connex}) if every pair is comparable:
\[
\forall a,b \in A, \;
(a,b) \in R \lor (b,a) \in R.
\]

\label{def:transitive}
$R$ is \emph{transitive} if it extends along chains:
\[
\forall a,b,c \in A, \;
\bigl( (a,b) \in R \land (b,c) \in R \bigr) \rightarrow (a,c) \in R.
\]

